16.         if (orderTotal >= 500m)
17.             return orderTotal * 0.10m;
18.         if (orderTotal >= 100m)
19.             return orderTotal * 0.05m;
20. 
21.         return 0m;
22.     }
23. 
24.     /// <summary>
25.     /// Calculates shipping cost. Free shipping for orders over 250.
26.     /// Express adds 50% surcharge. Items over 10kg add a heavy item fee.
27.     /// </summary>
28.     public decimal CalculateShipping(decimal orderTotal, double weightKg, bool express)
29.     {
30.         if (orderTotal <= 0)
31.             throw new ArgumentOutOfRangeException(nameof(orderTotal));
32.         if (weightKg <= 0)
33.             throw new ArgumentOutOfRangeException(nameof(weightKg));
34. 
35.         if (orderTotal > 250m)
36.             return 0m;
37. 
38.         decimal baseCost = 5.00m + (decimal)(weightKg * 0.50);
39. 
40.         if (weightKg > 10.0)
41.             baseCost += 15.00m;
42. 
43.         if (express)
44.             baseCost *= 1.50m;
45. 
46.         return baseCost;
47.     }
48. 
