50.     /// Applies a coupon code. Returns the adjusted total after coupon.
51.     /// Coupons cannot reduce the total below 1.00.
52.     /// </summary>
53.     public decimal ApplyCoupon(decimal total, string couponCode)
54.     {
55.         ArgumentNullException.ThrowIfNull(couponCode);
56. 
57.         if (total <= 0)
58.             throw new ArgumentOutOfRangeException(nameof(total));
59. 
60.         decimal discount = couponCode.ToUpperInvariant() switch
61.         {
62.             "SAVE10" => total * 0.10m,
63.             "SAVE20" => total * 0.20m,
64.             "FLAT5" => 5.00m,
65.             "FLAT50" => 50.00m,
66.             _ => 0m
