     // -- CalculateShipping tests --

     [TestMethod]
     public void CalculateShipping_LargeOrder_FreeShipping()
     {
         var calc = new DiscountCalculator();
         var cost = calc.CalculateShipping(500m, 2.0, false);
         Assert.AreEqual(0m, cost);
     }

     [TestMethod]
     public void CalculateShipping_SmallOrder_ReturnsBaseCost()
     {
         var calc = new DiscountCalculator();
         var cost = calc.CalculateShipping(50m, 2.0, false);
         Assert.AreEqual(6.00m, cost);
     }

     [TestMethod]
     public void CalculateShipping_ZeroWeight_Throws()
     {
         var calc = new DiscountCalculator();
         Assert.ThrowsExactly<ArgumentOutOfRangeException>(
             () => calc.CalculateShipping(50m, 0, false));
     }

     [TestMethod]
     public void CalculateShipping_ZeroTotal_Throws()
     {
         var calc = new DiscountCalculator();
         Assert.ThrowsExactly<ArgumentOutOfRangeException>(
             () => calc.CalculateShipping(0m, 2.0, false));
     }

     // Boundary: exactly 250 should NOT be free (> 250, not >=)
     [TestMethod]
     public void CalculateShipping_Exactly250_NotFree()
     {
         var calc = new DiscountCalculator();
         var cost = calc.CalculateShipping(250m, 2.0, false);
         Assert.AreNotEqual(0m, cost);
     }

     [TestMethod]
     public void CalculateShipping_JustAbove250_FreeShipping()
     {
         var calc = new DiscountCalculator();
         Assert.AreEqual(0m, calc.CalculateShipping(250.01m, 2.0, false));
     }

     // Heavy item fee (> 10kg)
     [TestMethod]
     public void CalculateShipping_HeavyItem_AddsHeavyFee()
     {
         var calc = new DiscountCalculator();
         // 5.00 + (11 * 0.50) + 15.00 = 25.50
         Assert.AreEqual(25.50m, calc.CalculateShipping(50m, 11.0, false));
     }

     [TestMethod]
     public void CalculateShipping_Exactly10kg_NoHeavyFee()
     {
         var calc = new DiscountCalculator();
         // 5.00 + (10 * 0.50) = 10.00
         Assert.AreEqual(10.00m, calc.CalculateShipping(50m, 10.0, false));
     }

     // Express surcharge
     [TestMethod]
     public void CalculateShipping_Express_Adds50PercentSurcharge()
     {
         var calc = new DiscountCalculator();
         // (5.00 + 2*0.50) * 1.50 = 9.00
         Assert.AreEqual(9.00m, calc.CalculateShipping(50m, 2.0, true));
     }

     [TestMethod]
     public void CalculateShipping_HeavyExpress_CombinesFees()
     {
         var calc = new DiscountCalculator();
         // (5.00 + 11*0.50 + 15.00) * 1.50 = 25.50 * 1.50 = 38.25
         Assert.AreEqual(38.25m, calc.CalculateShipping(50m, 11.0, true));
     }

     // -- ApplyCoupon tests --

     [TestMethod]
     public void ApplyCoupon_Save10_Applies10Percent()
     {
         var calc = new DiscountCalculator();
         var result = calc.ApplyCoupon(100m, "SAVE10");
         Assert.AreEqual(90m, result);
     }

     [TestMethod]
     public void ApplyCoupon_Flat50_SubtractsFifty()
     {
         var calc = new DiscountCalculator();
         var result = calc.ApplyCoupon(200m, "FLAT50");
         Assert.AreEqual(150m, result);
     }

     [TestMethod]
     public void ApplyCoupon_NullCoupon_Throws()
     {
         var calc = new DiscountCalculator();
         Assert.ThrowsExactly<ArgumentNullException>(
             () => calc.ApplyCoupon(100m, null!));
     }

     [TestMethod]
     public void ApplyCoupon_ZeroTotal_Throws()
     {
         var calc = new DiscountCalculator();
         Assert.ThrowsExactly<ArgumentOutOfRangeException>(
             () => calc.ApplyCoupon(0m, "SAVE10"));
     }

     // Unknown coupon returns original total
     [TestMethod]
     public void ApplyCoupon_UnknownCode_ReturnsOriginalTotal()
     {
         var calc = new DiscountCalculator();
         Assert.AreEqual(100m, calc.ApplyCoupon(100m, "BOGUS"));
     }

     // Minimum floor: coupon can't reduce below 1.00
     [TestMethod]
     public void ApplyCoupon_Flat50OnSmallTotal_FloorsAt1()
     {
         var calc = new DiscountCalculator();
         Assert.AreEqual(1.00m, calc.ApplyCoupon(10m, "FLAT50"));
     }

     [TestMethod]
     public void ApplyCoupon_Save20_Applies20Percent()
     {
         var calc = new DiscountCalculator();
         Assert.AreEqual(80m, calc.ApplyCoupon(100m, "SAVE20"));
     }

     [TestMethod]
     public void ApplyCoupon_Flat5_SubtractsFive()
     {
         var calc = new DiscountCalculator();
         Assert.AreEqual(95m, calc.ApplyCoupon(100m, "FLAT5"));
     }

     // Case-insensitive coupon handling
     [TestMethod]
     public void ApplyCoupon_LowercaseCode_StillApplies()
     {
         var calc = new DiscountCalculator();
         Assert.AreEqual(90m, calc.ApplyCoupon(100m, "save10"));
     }
 }

